// === store/discovery-core.js ===
// Shared storefront state, data normalization, modal, favorites and header counters.
(()=>{
  'use strict';
  if(window.AlinStoreDiscovery)return;

  const FAV_KEY='alin_v99_favorites';
  const state={
    filters:{kind:'',grade:'',subject:'',teacher:'',min:'',max:'',available:'',badge:'',sort:'recommended'},
    tables:{},schema:{},timer:null,modalReturnFocus:null,catalogSignature:''
  };
  const $=selector=>document.querySelector(selector);
  const $$=selector=>[...document.querySelectorAll(selector)];
  const esc=value=>String(value??'').replace(/[&<>"']/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[char]));
  const num=value=>Number(value)||0;
  const fmt=value=>new Intl.NumberFormat(window.AlinI18n?.locale?.()||'ar-IQ').format(num(value));
  const now=()=>Date.now();
  const imageUrl=path=>{try{return path?(typeof mediaUrl==='function'?mediaUrl(path):path):''}catch(_){return path||''}};
  const teacherBy=id=>(window.db?.accounts?.teachers||[]).find(row=>String(row.id)===String(id));
  const statusVisible=status=>!['hidden','inactive','deleted','archived','draft'].includes(String(status||'published'));
  const hasSb=()=>typeof window.sb!=='undefined'&&!!window.sb;
  const isDesktop=()=>document.body.classList.contains('store-desktop');
  const isMobile=()=>document.body.classList.contains('store-mobile');
  const stableKey=(kind,id)=>`${kind}:${id}`;

  function orderCounts(){
    const counts={};
    for(const order of window.db?.orders||[]){
      const key=`${order.kind}:${order.item_id}`;
      counts[key]=(counts[key]||0)+num(order.qty||1);
    }
    return counts;
  }

  function canonicalItems(){
    const counts=orderCounts();
    const booklets=(window.db?.booklets||[]).filter(row=>statusVisible(row.status)).map(row=>{
      const teacher=teacherBy(row.teacher_id)||{};
      return {
        kind:'booklet',id:String(row.id),raw:row,title:row.title||'ملزمة',teacher:teacher.name||'',teacherId:row.teacher_id||'',
        subject:row.subject||'',grade:row.grade||'',category:'ملازم',price:num(row.price),originalPrice:num(row.original_price),
        stock:row.stock==null?null:num(row.stock),image:row.cover_path||row.image_path||'',cover:row.cover_path||row.image_path||'',
        created:row.created_at||'',sold:num(row.sales_count)||counts[`booklet:${row.id}`]||0,badge:row.badge||'',prep:num(row.prep_minutes),
        dealPrice:num(row.deal_price),dealStart:row.deal_start,dealEnd:row.deal_end,description:row.description||'',status:row.status
      };
    });
    const products=(window.db?.products||[]).filter(row=>statusVisible(row.status)).map(row=>({
      kind:row.type||'product',id:String(row.id),raw:row,title:row.name||row.title||'منتج',teacher:row.teacher||'',teacherId:row.teacher_id||'',
      subject:row.subject||row.category||'',grade:row.grade||'',category:row.category||row.type||'',price:num(row.price),originalPrice:num(row.original_price),
      stock:row.stock==null?null:num(row.stock),image:row.image_path||row.cover_path||'',cover:row.image_path||row.cover_path||'',created:row.created_at||'',
      sold:num(row.sales_count)||counts[`${row.type||'product'}:${row.id}`]||counts[`product:${row.id}`]||0,badge:row.badge||'',prep:num(row.prep_minutes),
      dealPrice:num(row.deal_price),dealStart:row.deal_start,dealEnd:row.deal_end,description:row.description||'',status:row.status
    }));
    return [...booklets,...products];
  }

  function activeDeal(item){
    const time=now();
    const start=item.dealStart?Date.parse(item.dealStart):0;
    const end=item.dealEnd?Date.parse(item.dealEnd):0;
    return item.dealPrice>0&&item.dealPrice<item.price&&(!start||start<=time)&&(!end||end>=time);
  }
  const effectivePrice=item=>activeDeal(item)?item.dealPrice:item.price;
  const badges=item=>[
    item.badge,activeDeal(item)?'عرض اليوم':'',item.sold>=5?'الأكثر طلباً':'',
    item.created&&Date.now()-Date.parse(item.created)<30*864e5?'جديد':'',
    item.stock!==null&&item.stock>0&&item.stock<=5?'كمية محدودة':''
  ].filter(Boolean);

  function findItem(kind,id){
    const rows=canonicalItems();
    return rows.find(item=>item.kind===kind&&item.id===String(id))||rows.find(item=>item.id===String(id));
  }

  function favoriteKeys(){
    let rows=[];
    for(const key of [FAV_KEY,'alin_v98_favorites','alin_v85_favorites','ALIN_FAVORITES']){
      try{
        const parsed=JSON.parse(localStorage.getItem(key)||'[]');
        if(Array.isArray(parsed))rows.push(...parsed.map(value=>typeof value==='string'?value:stableKey(value.kind,value.id)));
      }catch(_){/* ignore malformed legacy storage */}
    }
    rows=[...new Set(rows.map(String).filter(Boolean))];
    localStorage.setItem(FAV_KEY,JSON.stringify(rows));
    try{localStorage.setItem('alin_v98_favorites',JSON.stringify(rows))}catch(_){/* ignore */}
    return rows;
  }
  const favoriteItems=()=>favoriteKeys().map(key=>{const [kind,...id]=key.split(':');return findItem(kind,id.join(':'))}).filter(Boolean);
  const isFavorite=item=>favoriteKeys().includes(stableKey(item.kind,item.id));

  function closeModal(restore=true){
    const modal=$('.v99-modal');
    if(!modal)return;
    modal.remove();
    document.body.classList.remove('v99-modal-open');
    if(restore&&state.modalReturnFocus?.isConnected)state.modalReturnFocus.focus();
    state.modalReturnFocus=null;
  }
  function openModal(html){
    const existing=$('.v99-modal');
    if(!existing)state.modalReturnFocus=document.activeElement;else existing.remove();
    const modal=document.createElement('div');
    modal.className='v99-modal';
    modal.setAttribute('role','presentation');
    modal.innerHTML=`<div class="v99-modal-card" role="dialog" aria-modal="true" tabindex="-1"><button class="v99-close" type="button" data-v99-action="close" aria-label="إغلاق النافذة">×</button>${html}</div>`;
    const title=modal.querySelector('h2');
    const dialog=modal.querySelector('[role="dialog"]');
    if(title){title.id='v99DialogTitle';dialog?.setAttribute('aria-labelledby','v99DialogTitle')}else dialog?.setAttribute('aria-label','نافذة متجر آلين');
    document.body.appendChild(modal);
    document.body.classList.add('v99-modal-open');
    requestAnimationFrame(()=>dialog?.focus());
    return modal;
  }

  function studentProfile(){
    try{return JSON.parse(localStorage.getItem('alin_v99_student_profile')||'{}')}catch(_){return{}}
  }

  function updateDesktopHeader(){
    if(!isDesktop())return;
    const favoriteCount=favoriteItems().length;
    const favoriteBadge=$('#v99DesktopFavoriteCount');
    if(favoriteBadge){favoriteBadge.textContent=fmt(favoriteCount);favoriteBadge.hidden=!favoriteCount}
    const cartCount=Array.isArray(window.cart)?window.cart.reduce((sum,item)=>sum+Math.max(1,num(item.qty)),0):0;
    const cartBadge=$('#desktopCartCount');
    if(cartBadge){cartBadge.textContent=fmt(cartCount);cartBadge.hidden=!cartCount}
    let student=null;
    try{student=typeof window.currentStudent==='function'?window.currentStudent():null}catch(_){/* ignore */}
    const button=$('#studentAuthBtn'),status=$('#studentAuthStatus');
    if(button)button.innerHTML=`<span class="desktop-account-icon" aria-hidden="true"></span><small>${esc(student?.name||'تسجيل الدخول')}</small>`;
    if(status)status.textContent=student?`مرحباً ${student.name}`:'التسجيل اختياري';
  }

  function updateMobileHeader(){
    if(!isMobile())return;
    const favoriteCount=favoriteItems().length;
    const favoriteBadge=$('#mobileFavoriteCount');
    if(favoriteBadge){favoriteBadge.textContent=fmt(favoriteCount);favoriteBadge.hidden=!favoriteCount}
    const cartCount=Array.isArray(window.cart)?window.cart.reduce((sum,item)=>sum+Math.max(1,num(item.qty)),0):0;
    const cartBadge=$('#mobileBottomCartCount')||$('#mobileCartCount');
    if(cartBadge){cartBadge.textContent=fmt(cartCount);cartBadge.hidden=!cartCount}
    let student=null;
    try{student=typeof window.currentStudent==='function'?window.currentStudent():null}catch(_){/* ignore */}
    const button=$('#studentAuthBtn'),status=$('#studentAuthStatus');
    if(button)button.innerHTML=`<span class="mobile-account-icon" aria-hidden="true"></span><small>${esc(student?.name||'الحساب')}</small>`;
    if(status)status.textContent=student?`مرحباً ${student.name}`:'التسجيل اختياري';
  }

  const api={FAV_KEY,state,$,$$,esc,num,fmt,now,imageUrl,teacherBy,statusVisible,hasSb,isDesktop,isMobile,stableKey,canonicalItems,activeDeal,effectivePrice,badges,findItem,favoriteKeys,favoriteItems,isFavorite,openModal,closeModal,studentProfile,updateDesktopHeader,updateMobileHeader};
  window.AlinStoreDiscovery=api;

  window.v99ToggleFavorite=(kind,id)=>{
    const key=stableKey(kind,id);
    let rows=favoriteKeys();
    rows=rows.includes(key)?rows.filter(row=>row!==key):[...rows,key];
    localStorage.setItem(FAV_KEY,JSON.stringify(rows));
    try{localStorage.setItem('alin_v98_favorites',JSON.stringify(rows))}catch(_){/* ignore */}
    api.renderEffectiveStore?.();
    updateDesktopHeader();
    updateMobileHeader();
    if(typeof window.toast==='function')window.toast(rows.includes(key)?'تمت الإضافة إلى المفضلة':'تمت الإزالة من المفضلة');
  };

  window.v99ShowFavorites=()=>{
    const rows=favoriteItems();
    const cards=rows.map(item=>api.miniCard?.(item)||'').join('');
    openModal(`<section class="v99-desktop-favorites"><h2>المفضلة</h2>${rows.length?`<p class="muted">${fmt(rows.length)} مادة محفوظة للعودة إليها بسهولة.</p><div class="v99-rail">${cards}</div>`:`<div class="v99-favorites-empty"><span aria-hidden="true">آ</span><h3>مفضلتك جاهزة لاختياراتك</h3><p>احفظ المواد والمنتجات التي تهمك لتجدها هنا في أي وقت.</p><button type="button" data-v99-action="browseProducts">تصفح المنتجات</button></div>`}</section>`);
  };
})();

;
/* modules/store/discovery-catalog.js */
// === store/discovery-catalog.js ===
// Store catalog rendering, filters, categories, rails and public statistics.
(()=>{
  'use strict';
  const ctx=window.AlinStoreDiscovery;
  if(!ctx)throw new Error('AlinStoreDiscovery core must load before catalog');
  const {$,$$,esc,num,fmt,imageUrl,state,canonicalItems,activeDeal,effectivePrice,badges,isFavorite,statusVisible,isDesktop,isMobile,studentProfile,updateDesktopHeader,updateMobileHeader}=ctx;

  function card(item){
    const out=item.stock!==null&&item.stock<=0;
    const price=effectivePrice(item);
    return `<article class="v99-product-card" data-v99-item="${esc(ctx.stableKey(item.kind,item.id))}">
      <button class="v99-fav" type="button" data-v99-action="favorite" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}" aria-label="المفضلة">${isFavorite(item)?'♥':'♡'}</button>
      <button class="v99-product-media" type="button" data-v99-action="details" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}" aria-label="عرض تفاصيل ${esc(item.title)}">${item.image?`<img src="${esc(imageUrl(item.image))}" alt="" loading="lazy">`:'<span class="v99-placeholder" aria-hidden="true">آ</span>'}</button>
      <div class="v99-product-body"><div class="v99-badges">${badges(item).map(label=>`<span class="v99-badge ${label==='كمية محدودة'?'stock':''}">${esc(label)}</span>`).join('')}</div>
        <h3><button class="v99-title-button" type="button" data-v99-action="details" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">${esc(item.title)}</button></h3>
        <p>${esc([item.teacher,item.subject,item.grade].filter(Boolean).join(' • '))}</p>
        <div class="v99-card-meta"><span class="v99-stock ${out?'out':''}">${item.stock===null?'متاح':out?'نافد':`متوفر: ${fmt(item.stock)}`}</span><span>${item.prep?`تجهيز ${fmt(item.prep)} د`:'تجهيز حسب المكتبة'}</span></div>
        <div class="v99-card-price">${fmt(price)} د.ع ${activeDeal(item)?`<del>${fmt(item.price)}</del>`:''}</div>
        <div class="v99-actions"><button class="${out?'v99-alert-action':''}" data-v99-action="cart" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">${out?'أبلغني':'أضف للسلة'}</button><button class="v99-secondary" data-v99-action="details" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">التفاصيل</button></div>
      </div></article>`;
  }

  function matches(item){
    const filters=state.filters;
    const query=String($('#searchInput')?.value||'').trim().toLowerCase();
    const haystack=[item.title,item.teacher,item.subject,item.grade,item.category].join(' ').toLowerCase();
    return (!query||haystack.includes(query))
      &&(!filters.kind||item.kind===filters.kind||item.category===filters.kind)
      &&(!filters.grade||item.grade===filters.grade)
      &&(!filters.subject||item.subject===filters.subject)
      &&(!filters.teacher||String(item.teacherId)===filters.teacher)
      &&(!filters.min||effectivePrice(item)>=num(filters.min))
      &&(!filters.max||effectivePrice(item)<=num(filters.max))
      &&(!filters.available||(filters.available==='yes'?(item.stock===null||item.stock>0):item.stock===0))
      &&(!filters.badge||(filters.badge==='deal'?activeDeal(item):badges(item).includes(filters.badge)));
  }

  function sorted(rows){
    const mode=state.filters.sort;
    return rows.sort((a,b)=>mode==='newest'?String(b.created).localeCompare(String(a.created))
      :mode==='best'?b.sold-a.sold
      :mode==='priceAsc'?effectivePrice(a)-effectivePrice(b)
      :mode==='priceDesc'?effectivePrice(b)-effectivePrice(a)
      :(Number(activeDeal(b))-Number(activeDeal(a)))||(b.sold-a.sold));
  }

  function options(rows,key,label,value=item=>item[key]){
    const values=[...new Map(rows.map(item=>[String(value(item)||''),String(value(item)||'')])).values()].filter(Boolean).sort();
    return `<option value="">${label}</option>${values.map(item=>`<option value="${esc(item)}">${esc(item)}</option>`).join('')}`;
  }

  function renderFilters(){
    const root=$('#v99DiscoveryTools');
    if(!root)return;
    const rows=canonicalItems();
    const teachers=(window.db?.accounts?.teachers||[]).filter(row=>row.status==='active'||!row.status);
    const desktop=isDesktop(),mobile=isMobile();
    if(desktop||mobile){root.setAttribute('role','dialog');root.setAttribute('aria-modal','true');root.setAttribute('tabindex','-1')}
    if(desktop)root.setAttribute('aria-labelledby','v99FilterDrawerTitle');
    if(mobile)root.setAttribute('aria-labelledby','v99MobileFilterDrawerTitle');
    const drawerHead=desktop
      ?'<div class="v99-drawer-head"><h2 id="v99FilterDrawerTitle">فلترة المنتجات</h2><button type="button" class="v99-drawer-close" data-v99-action="closeDesktopFilters" aria-label="إغلاق لوحة الفلاتر">×</button></div>'
      :mobile
        ?'<div class="v99-mobile-drawer-head"><h2 id="v99MobileFilterDrawerTitle">فلترة المنتجات</h2><button type="button" class="v99-mobile-drawer-close" data-v99-action="closeMobileFilters" aria-label="إغلاق لوحة الفلاتر">×</button></div>'
        :'<button class="v99-filter-toggle" type="button" data-v99-action="toggleFilters" aria-expanded="false"><span>تصفية وفرز المنتجات</span><span class="v99-toggle-mark" aria-hidden="true">+</span></button>';
    root.innerHTML=`${drawerHead}<div id="v99ActiveFilters" class="v99-active-filters" aria-live="polite"></div><div class="v99-filters" aria-label="عوامل التصفية">
      <label><span>النوع أو القسم</span><select data-filter="kind">${options(rows,'kind','الكل',item=>item.kind)}</select></label>
      <label><span>المرحلة الدراسية</span><select data-filter="grade">${options(rows,'grade','كل المراحل')}</select></label>
      <label><span>المادة</span><select data-filter="subject">${options(rows,'subject','كل المواد')}</select></label>
      <label><span>المدرس</span><select data-filter="teacher"><option value="">كل المدرسين</option>${teachers.map(teacher=>`<option value="${esc(teacher.id)}">${esc(teacher.name)}</option>`).join('')}</select></label>
      <fieldset class="v99-price-range"><legend>نطاق السعر</legend><label><span>من</span><input data-filter="min" type="number" min="0" inputmode="numeric" placeholder="0"></label><label><span>إلى</span><input data-filter="max" type="number" min="0" inputmode="numeric" placeholder="بدون حد"></label></fieldset>
      <label><span>حالة التوفر</span><select data-filter="available"><option value="">الكل</option><option value="yes">متوفر</option><option value="no">نافد</option></select></label>
      <label><span>الشارة أو العرض</span><select data-filter="badge"><option value="">الكل</option><option value="deal">عرض اليوم</option><option>جديد</option><option>الأكثر طلباً</option><option>كمية محدودة</option></select></label>
      <label class="v99-sort-control"><span>ترتيب النتائج</span><select data-filter="sort"><option value="recommended">الموصى بها</option><option value="newest">الأحدث</option><option value="best">الأكثر مبيعاً</option><option value="priceAsc">السعر: الأقل</option><option value="priceDesc">السعر: الأعلى</option></select></label>
      </div><div class="v99-filter-actions"><span class="v99-filter-summary" id="v99FilterSummary"></span><button type="button" class="v99-secondary" data-v99-action="clearFilters">مسح الكل</button></div>`;
    syncFilterControls();
    renderFilterChips();
  }

  function syncFilterControls(){
    $$('[data-filter]').forEach(element=>{element.value=state.filters[element.dataset.filter]||''});
  }

  function renderFilterChips(){
    const root=$('#v99ActiveFilters');
    const activeRows=Object.entries(state.filters).filter(([key,value])=>value&&!(key==='sort'&&value==='recommended'));
    if(root){
      const labels={kind:'النوع',grade:'المرحلة',subject:'المادة',teacher:'المدرس',min:'من',max:'إلى',available:'التوفر',badge:'العرض',sort:'الترتيب'};
      const visible=(key,value)=>{
        if(key==='min'||key==='max')return `${fmt(value)} د.ع`;
        const control=$(`[data-filter="${key}"]`);
        const option=[...(control?.options||[])].find(row=>row.value===String(value));
        return option?.textContent?.trim()||String(value);
      };
      root.innerHTML=activeRows.map(([key,value])=>`<button type="button" data-v99-action="removeFilter" data-filter-key="${esc(key)}" aria-label="إزالة فلتر ${esc(labels[key])}">${esc(labels[key])}: ${esc(visible(key,value))} <span aria-hidden="true">×</span></button>`).join('');
      root.hidden=!activeRows.length;
    }
    for(const id of ['v99DesktopFilterCount','v99MobileFilterCount']){
      const count=$(`#${id}`);
      if(count){count.textContent=fmt(activeRows.length);count.hidden=!activeRows.length}
    }
  }

  function miniCard(item){
    return `<article class="v99-mini-card"><div class="v99-mini-media">${item.image?`<img src="${esc(imageUrl(item.image))}" alt="">`:'<span class="v99-placeholder">آ</span>'}</div><div class="v99-mini-body"><div class="v99-badges">${badges(item).slice(0,2).map(label=>`<span class="v99-badge">${esc(label)}</span>`).join('')}</div><h3>${esc(item.title)}</h3><p>${esc([item.teacher,item.subject,item.grade].filter(Boolean).join(' • '))}</p><div class="v99-card-price">${fmt(effectivePrice(item))} د.ع</div><button data-v99-action="details" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">عرض</button></div></article>`;
  }

  function rail(rootSelector,title,subtitle,rows){
    const root=$(rootSelector);
    if(!root)return;
    if(!rows.length){root.innerHTML='';return}
    root.innerHTML=`<div class="v99-section-head"><div><h2>${esc(title)}</h2><small>${esc(subtitle)}</small></div></div><div class="v99-rail">${rows.map(miniCard).join('')}</div>`;
  }

  function renderStage(){
    const root=$('#v99Personalized');
    if(!root)return;
    if(isMobile()){root.replaceChildren();root.hidden=true;return}
    root.hidden=false;
    const profile=studentProfile();
    const grades=[...new Set(canonicalItems().map(item=>item.grade).filter(Boolean))];
    root.innerHTML=`<div class="v99-stage-strip"><div><h2>مواد تناسب مرحلتك</h2><p>${profile.grade?`نعرض لك اختيارات ${esc(profile.grade)} أولاً.`:'اختر مرحلتك لتحصل على اقتراحات أقرب لدراستك.'}</p></div><select id="v99GradeSelect" aria-label="المرحلة الدراسية"><option value="">كل المراحل</option>${grades.map(grade=>`<option ${grade===profile.grade?'selected':''}>${esc(grade)}</option>`).join('')}</select></div><div id="v99PersonalizedItems" class="v99-rail-root"></div>`;
  }

  function updateCountdowns(){
    $$('[data-deal-end]').forEach(element=>{
      const end=Date.parse(element.dataset.dealEnd);
      if(!end){element.textContent='لفترة محدودة';return}
      const remaining=Math.max(0,end-ctx.now());
      const hours=Math.floor(remaining/36e5),minutes=Math.floor((remaining%36e5)/6e4),seconds=Math.floor((remaining%6e4)/1000);
      element.textContent=remaining?`ينتهي خلال ${fmt(hours)}:${String(minutes).padStart(2,'0')}:${String(seconds).padStart(2,'0')}`:'انتهى العرض';
    });
  }

  function renderDeal(){
    const root=$('#v99DailyDeals');
    if(!root)return;
    const item=canonicalItems().filter(activeDeal).sort((a,b)=>(b.price-b.dealPrice)-(a.price-a.dealPrice))[0];
    if(!item){root.innerHTML='';return}
    root.innerHTML=`<article class="v99-deal-feature"><div class="v99-deal-media">${item.image?`<img src="${esc(imageUrl(item.image))}" alt="${esc(item.title)}">`:'<span class="v99-placeholder">ALIN</span>'}</div><div class="v99-deal-copy"><span class="v99-kicker">عرض اليوم</span><h2>${esc(item.title)}</h2><p>${esc([item.teacher,item.subject,item.grade].filter(Boolean).join(' • '))}</p><div class="v99-price">${fmt(item.dealPrice)} د.ع <del>${fmt(item.price)}</del></div><div class="v99-countdown" data-deal-end="${esc(item.dealEnd||'')}"></div><div class="v99-actions"><button data-v99-action="cart" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">أضف للسلة</button><button class="v99-secondary" data-v99-action="share" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">مشاركة</button></div></div></article>`;
    updateCountdowns();
  }

  function publicTeachers(){
    return (window.db?.accounts?.teachers||[]).filter(teacher=>teacher.public_profile===false?false:(teacher.status==='active'||teacher.status==='approved'||!teacher.status));
  }

  function renderTeachers(){
    const root=$('#v99TeacherRail'),rows=publicTeachers();
    if(!root)return;
    if(isDesktop()||isMobile()){root.innerHTML='';root.hidden=true;return}
    if(!rows.length){root.innerHTML='';return}
    root.innerHTML=`<div class="v99-section-head"><div><h2>مدرسون مميزون</h2><small>تعرّف على المدرس وملزماته</small></div></div><div class="v99-rail">${rows.slice(0,10).map(teacher=>`<article class="v99-teacher-card" data-v99-action="teacher" data-id="${esc(teacher.id)}"><span class="v99-avatar">${teacher.avatar_path||teacher.image_path?`<img src="${esc(imageUrl(teacher.avatar_path||teacher.image_path))}" alt="">`:esc((teacher.name||'آ').slice(0,1))}</span><span><b>${esc(teacher.name)}</b><small>${esc(teacher.specialty||teacher.subject||'مدرس معتمد')}</small></span></article>`).join('')}</div>`;
  }

  function renderBundles(){
    const root=$('#v99Bundles');
    if(!root)return;
    const bundles=state.tables.bundles||[],items=state.tables.bundle_items||[];
    const active=bundles.filter(bundle=>bundle.active!==false&&statusVisible(bundle.status));
    if(!active.length){root.innerHTML='';return}
    root.innerHTML=`<div class="v99-section-head"><div><h2>حزم أوفر</h2><small>مجموعة مواد بسعر واحد</small></div></div><div class="v99-rail">${active.map(bundle=>{const count=items.filter(item=>String(item.bundle_id)===String(bundle.id)).length;return `<article class="v99-mini-card"><div class="v99-mini-body"><span class="v99-kicker">حزمة ${fmt(count)} مواد</span><h3>${esc(bundle.name||bundle.title)}</h3><p>${esc(bundle.description||'اختيار متكامل بسعر مخفّض')}</p><div class="v99-card-price">${fmt(bundle.bundle_price||bundle.price)} د.ع</div><button data-v99-action="bundle" data-id="${esc(bundle.id)}">عرض الحزمة</button></div></article>`}).join('')}</div>`;
  }

  function renderRails(){
    const rows=canonicalItems(),grade=studentProfile().grade;
    let newest=rows;
    if(isDesktop()||isMobile()){
      if(state.filters.badge==='deal')newest=newest.filter(activeDeal);
      else if(state.filters.kind)newest=newest.filter(item=>item.kind===state.filters.kind);
    }
    rail('#v99NewArrivals','وصل حديثاً','أحدث المواد المضافة',newest.filter(item=>item.created).sort((a,b)=>String(b.created).localeCompare(String(a.created))).slice(0,8));
    const bestBase=isDesktop()||isMobile()?rows.filter(item=>item.kind==='stationery'||item.kind==='gift'):rows;
    rail('#v99BestSellers','الأكثر طلباً','اختيارات الطلاب الأكثر رواجاً',[...bestBase].sort((a,b)=>b.sold-a.sold).filter(item=>item.sold>0).slice(0,8));
    renderTeachers();
    renderBundles();
    if(grade)rail('#v99PersonalizedItems','حسب مرحلتي','',rows.filter(item=>item.grade===grade).slice(0,8));
  }

  function visibleAccount(row){
    if(!row||row.deleted_at)return false;
    return !['inactive','disabled','suspended','rejected','deleted','archived'].includes(String(row.status||'active').trim().toLowerCase());
  }
  function uniqueVisibleCount(rows){
    const seen=new Set();
    for(const row of rows||[]){
      if(!visibleAccount(row))continue;
      const key=String(row.id||row.auth_user_id||row.username||row.phone||row.name||'').trim();
      if(key)seen.add(key);
    }
    return seen.size;
  }
  function renderStoreStats(){
    const booklets=(window.db?.booklets||[]).filter(row=>statusVisible(row.status)&&!row.deleted_at).length;
    const teachers=uniqueVisibleCount(window.db?.accounts?.teachers||[]);
    const libraries=uniqueVisibleCount(window.db?.accounts?.libraries||[]);
    const values={alinStatBooklets:booklets,alinStatTeachers:teachers,alinStatLibraries:libraries};
    for(const [id,value] of Object.entries(values)){const node=document.getElementById(id);if(node)node.textContent=fmt(value)}
    return values;
  }

  function syncCategoryUI(prefix){
    const active=state.filters.badge==='deal'?'deal':state.filters.kind||'';
    const labels={booklet:['الملازم','كل الملازم المتاحة'],stationery:['القرطاسية','منتجات القرطاسية'],gift:['الهدايا','هدايا مختارة'],deal:['العروض','العروض الفعالة الآن']};
    const copy=labels[active]||['كل المنتجات','الكتالوج الكامل'];
    $$('[data-v99-category]').forEach(button=>button.setAttribute('aria-pressed',String(button.dataset.v99Category===active)));
    const title=$(`#${prefix}CatalogTitle`),kicker=$(`#${prefix}CatalogKicker`);
    if(title)title.textContent=copy[0];
    if(kicker)kicker.textContent=copy[1];
  }
  const syncDesktopCategoryUI=()=>{if(isDesktop())syncCategoryUI('v99')};
  const syncMobileCategoryUI=()=>{if(isMobile())syncCategoryUI('v99Mobile')};

  function renderEffectiveStore(){
    const grid=$('#storeGrid');
    if(!grid)return [];
    const rows=sorted(canonicalItems().filter(matches));
    grid.innerHTML=rows.map(card).join('')||'<div class="v99-empty"><b>لا توجد نتائج مطابقة</b><p>غيّر عوامل التصفية أو امسحها للعودة إلى جميع المواد.</p></div>';
    const summary=$('#v99FilterSummary');
    if(summary)summary.textContent=`${fmt(rows.length)} نتيجة`;
    renderFilterChips();
    syncDesktopCategoryUI();
    syncMobileCategoryUI();
    renderDeal();
    renderRails();
    updateDesktopHeader();
    updateMobileHeader();
    renderStoreStats();
    document.dispatchEvent(new CustomEvent('alin:store-rendered',{detail:{count:rows.length,source:'store-discovery'}}));
    return rows;
  }

  function normalizedStoreType(type){
    const value=String(type||'').trim().toLowerCase();
    if(['gift','gifts'].includes(value))return 'gift';
    if(['stationery','stationary'].includes(value))return 'stationery';
    if(['booklet','booklets'].includes(value))return 'booklet';
    return value;
  }
  function currentStoreItems(){
    const type=normalizedStoreType(window.db?.settings?.storeType||'');
    const rows=canonicalItems();
    if(!type)return rows;
    return rows.filter(item=>normalizedStoreType(item.kind)===type||normalizedStoreType(item.category)===type);
  }
  function renderStore(){
    const signature=`${(window.db?.booklets||[]).length}:${(window.db?.products||[]).length}:${(window.db?.accounts?.teachers||[]).length}`;
    if(state.catalogSignature!==signature){state.catalogSignature=signature;renderFilters();renderStage()}
    ctx.renderStudentHub?.();
    return renderEffectiveStore();
  }
  function setStoreType(type,button){
    const value=normalizedStoreType(type)||'booklet';
    window.db.settings=window.db.settings||{};
    window.db.settings.storeType=value;
    state.filters.kind=value;
    state.filters.badge='';
    if(button){document.querySelectorAll('[data-v99-category],.store-nav button').forEach(node=>node.classList.remove('active'));button.classList.add('active')}
    syncFilterControls();
    return renderStore();
  }

  Object.assign(ctx,{card,matches,sorted,renderFilters,syncFilterControls,renderFilterChips,miniCard,rail,renderStage,renderDeal,renderRails,renderStoreStats,syncDesktopCategoryUI,syncMobileCategoryUI,renderEffectiveStore,normalizedStoreType,currentStoreItems,renderStore,setStoreType,publicTeachers,renderTeachers,renderBundles,updateCountdowns});
  window.storeItems=currentStoreItems;
  window.renderStore=renderStore;
  window.setStoreType=setStoreType;
  window.AlinStorefront=Object.freeze({render:renderStore,items:canonicalItems,currentItems:currentStoreItems,setType:setStoreType,stats:renderStoreStats,openDetails:(kind,id)=>window.v99OpenDetails?.(kind,id)});
})();

;
/* modules/store/discovery-details.js */
// === store/discovery-details.js ===
// Product details, related items, sharing, stock alerts, reviews and bundles.
(()=>{
  'use strict';
  const ctx=window.AlinStoreDiscovery;
  if(!ctx)throw new Error('AlinStoreDiscovery core must load before details');
  const {$,esc,num,fmt,imageUrl,state,canonicalItems,activeDeal,effectivePrice,badges,findItem,isFavorite,openModal,hasSb,stableKey}=ctx;

  const reviewsFor=item=>(state.tables.product_reviews||[]).filter(row=>row.kind===item.kind&&String(row.item_id)===item.id&&['approved','published'].includes(row.status||'approved'));
  function relatedItems(item){
    return canonicalItems().filter(candidate=>stableKey(candidate.kind,candidate.id)!==stableKey(item.kind,item.id)).map(candidate=>({
      item:candidate,
      score:(candidate.subject&&candidate.subject===item.subject?5:0)
        +(candidate.grade&&candidate.grade===item.grade?4:0)
        +(candidate.teacherId&&String(candidate.teacherId)===String(item.teacherId)?3:0)
        +(candidate.category&&candidate.category===item.category?2:0)
    })).filter(row=>row.score>0).sort((a,b)=>b.score-a.score).slice(0,6).map(row=>row.item);
  }
  function relatedDetailHtml(item){
    const rows=relatedItems(item);
    return rows.length?`<section class="v99-related"><div class="v99-section-head"><div><h2>مواد مرتبطة</h2><small>اقتراحات من نفس المادة أو المرحلة</small></div></div><div class="v99-rail">${rows.map(ctx.miniCard).join('')}</div></section>`:'';
  }

  function openDetails(kind,id){
    const item=findItem(kind,id);
    if(!item)return;
    const reviews=reviewsFor(item);
    const average=reviews.length?reviews.reduce((sum,row)=>sum+num(row.rating),0)/reviews.length:0;
    const out=item.stock!==null&&item.stock<=0;
    openModal(`<div class="v99-detail"><div class="v99-detail-media">${item.image?`<img src="${esc(imageUrl(item.image))}" alt="${esc(item.title)}">`:'<span class="v99-placeholder">ALIN</span>'}</div><div class="v99-detail-copy"><div class="v99-badges">${badges(item).map(label=>`<span class="v99-badge">${esc(label)}</span>`).join('')}</div><h2>${esc(item.title)}</h2><p>${esc([item.teacher,item.subject,item.grade,item.category].filter(Boolean).join(' • '))}</p><p>${esc(item.description||'مادة مختارة من متجر آلين، راجع التفاصيل وحدد طريقة الاستلام أو التوصيل عند إكمال الطلب.')}</p><div class="v99-price">${fmt(effectivePrice(item))} د.ع ${activeDeal(item)?`<del>${fmt(item.price)}</del>`:''}</div><div class="v99-card-meta"><span>${out?'غير متوفر حالياً':item.stock===null?'متاح للطلب':`المخزون ${fmt(item.stock)}`}</span><span>${item.prep?`تقدير التجهيز ${fmt(item.prep)} دقيقة`:'وقت التجهيز تؤكده المكتبة'}</span></div><div class="v99-notice">يمكنك اختيار الاستلام من المكتبة أو التوصيل عند إكمال الطلب. تبقى الكوبونات الحالية متاحة داخل السلة.</div><div class="v99-qty"><label for="v99DetailQty">الكمية</label><input id="v99DetailQty" type="number" min="1" max="99" value="1"></div><div class="v99-actions">${out?`<button data-v99-action="stockForm" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">أبلغني عند التوفر</button>`:`<button data-v99-action="cartQty" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">أضف للسلة</button><button class="v99-secondary" data-v99-action="buy" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">شراء الآن</button>`}<button class="v99-ghost" data-v99-action="share" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">مشاركة</button><button class="v99-ghost" data-v99-action="favorite" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">${isFavorite(item)?'إزالة من المفضلة':'حفظ بالمفضلة'}</button></div></div></div><section class="v99-reviews"><h3>التقييمات ${reviews.length?`— ${average.toFixed(1)} من 5`:''}</h3>${reviews.map(review=>`<div class="row"><div><b>${fmt(review.rating)} / 5</b><small>${esc(review.comment||'')}</small></div></div>`).join('')||'<p class="muted">لا توجد تقييمات منشورة بعد.</p>'}<button data-v99-action="reviewForm" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">أضف تقييمك</button></section>${relatedDetailHtml(item)}`);
  }

  async function shareItem(item){
    const url=new URL(location.href);
    url.hash='';
    url.searchParams.set('item',stableKey(item.kind,item.id));
    const data={title:item.title,text:`${item.title} — ${fmt(effectivePrice(item))} د.ع`,url:url.toString()};
    try{
      if(navigator.share)await navigator.share(data);
      else{await navigator.clipboard.writeText(`${data.text}\n${data.url}`);if(typeof window.toast==='function')window.toast('تم نسخ رابط المنتج')}
    }catch(error){if(error.name!=='AbortError')alert('تعذر نسخ الرابط')}
  }

  function stockForm(item){
    openModal(`<h2>أبلغني عند التوفر</h2><p>سنحفظ طلب التنبيه في النظام فقط إذا كانت الخدمة مفعلة.</p><div class="v99-form"><input id="v99StockContact" placeholder="رقم الهاتف"><button data-v99-action="stockSubmit" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">حفظ التنبيه</button><div id="v99FormMsg"></div></div>`);
  }
  async function stockSubmit(item){
    const contact=$('#v99StockContact')?.value.trim(),message=$('#v99FormMsg');
    if(!contact){if(message)message.innerHTML='<div class="v99-notice error">اكتب رقم الهاتف.</div>';return}
    if(!state.schema.stock_alerts||!hasSb()){if(message)message.innerHTML='<div class="v99-notice error">خدمة التنبيه غير مفعلة على قاعدة البيانات.</div>';return}
    try{
      const {error}=await window.sb.from('stock_alerts').insert({kind:item.kind,item_id:item.id,contact,status:'pending'});
      if(error)throw error;
      if(message)message.innerHTML='<div class="v99-notice success">تم تسجيل طلب التنبيه.</div>';
    }catch(error){if(message)message.innerHTML=`<div class="v99-notice error">لم يتم الحفظ: ${esc(error.message||'راجع إعدادات الخدمة')}</div>`}
  }

  function reviewForm(item){
    openModal(`<h2>قيّم ${esc(item.title)}</h2><div class="v99-form"><input id="v99ReviewContact" placeholder="رقم الهاتف"><select id="v99ReviewRating"><option value="5">5 — ممتاز</option><option value="4">4 — جيد جداً</option><option value="3">3 — جيد</option><option value="2">2 — مقبول</option><option value="1">1 — ضعيف</option></select><textarea id="v99ReviewComment" placeholder="اكتب رأيك"></textarea><button data-v99-action="reviewSubmit" data-kind="${esc(item.kind)}" data-id="${esc(item.id)}">إرسال للمراجعة</button><div id="v99FormMsg"></div></div>`);
  }
  async function reviewSubmit(item){
    const message=$('#v99FormMsg'),contact=$('#v99ReviewContact')?.value.trim(),rating=num($('#v99ReviewRating')?.value),comment=$('#v99ReviewComment')?.value.trim();
    if(!contact||!comment){if(message)message.innerHTML='<div class="v99-notice error">أكمل رقم الهاتف والتعليق.</div>';return}
    if(!state.schema.product_reviews||!hasSb()){if(message)message.innerHTML='<div class="v99-notice error">خدمة التقييمات غير مفعلة.</div>';return}
    try{
      const {error}=await window.sb.from('product_reviews').insert({kind:item.kind,item_id:item.id,student_contact:contact,rating,comment,status:'pending'});
      if(error)throw error;
      if(message)message.innerHTML='<div class="v99-notice success">تم إرسال تقييمك للمراجعة قبل النشر.</div>';
    }catch(error){if(message)message.innerHTML=`<div class="v99-notice error">لم يتم الإرسال: ${esc(error.message||'راجع إعدادات الخدمة')}</div>`}
  }

  function teacherModal(id){
    const teacher=ctx.publicTeachers?.().find(row=>String(row.id)===String(id));
    if(!teacher)return;
    const books=canonicalItems().filter(item=>item.kind==='booklet'&&String(item.teacherId)===String(id));
    openModal(`<div class="v99-detail"><div><span class="v99-avatar">${teacher.avatar_path||teacher.image_path?`<img src="${esc(imageUrl(teacher.avatar_path||teacher.image_path))}" alt="">`:esc((teacher.name||'آ').slice(0,1))}</span></div><div class="v99-detail-copy"><span class="v99-kicker">ملف المدرس</span><h2>${esc(teacher.name)}</h2><p><b>${esc(teacher.specialty||'مدرس معتمد')}</b></p><p>${esc(teacher.bio||'مدرس معتمد في منصة آلين.')}</p></div></div><div class="v99-rail">${books.map(ctx.miniCard).join('')||'<div class="v99-empty">لا توجد ملازم منشورة حالياً.</div>'}</div>`);
  }

  function bundleModal(id){
    const bundle=(state.tables.bundles||[]).find(row=>String(row.id)===String(id));
    if(!bundle)return;
    const lines=(state.tables.bundle_items||[]).filter(row=>String(row.bundle_id)===String(id));
    const mapped=lines.map(line=>({...line,item:findItem(line.kind,String(line.item_id))})).filter(row=>row.item);
    openModal(`<h2>${esc(bundle.name||bundle.title)}</h2><p>${esc(bundle.description||'')}</p><div>${mapped.map(row=>`<div class="row"><div><b>${esc(row.item.title)}</b><small>الكمية ${fmt(row.quantity||1)}</small></div><span>${fmt(effectivePrice(row.item))} د.ع</span></div>`).join('')||'<div class="v99-empty">لا توجد عناصر متاحة في هذه الحزمة.</div>'}</div><div class="v99-price">سعر الحزمة: ${fmt(bundle.bundle_price||bundle.price)} د.ع</div><button data-v99-action="bundleAdd" data-id="${esc(id)}" ${mapped.length?'':'disabled'}>أضف الحزمة للسلة</button>`);
  }

  function addBundle(id){
    const lines=(state.tables.bundle_items||[]).filter(row=>String(row.bundle_id)===String(id));
    for(const line of lines){for(let index=0;index<Math.max(1,num(line.quantity));index++)window.addToCart?.(line.kind,String(line.item_id))}
    ctx.updateDesktopHeader();
    ctx.updateMobileHeader();
    if(typeof window.toast==='function')window.toast('أضيفت عناصر الحزمة المتاحة إلى السلة');
  }

  Object.assign(ctx,{reviewsFor,relatedItems,relatedDetailHtml,openDetails,shareItem,stockForm,stockSubmit,reviewForm,reviewSubmit,teacherModal,bundleModal,addBundle});
  window.v99OpenDetails=openDetails;
})();

;
/* modules/store/discovery-growth.js */
// === store/discovery-growth.js ===
// Student hub, growth tables, group orders, merchandising and tracking extras.
(()=>{
  'use strict';
  const ctx=window.AlinStoreDiscovery;
  if(!ctx)throw new Error('AlinStoreDiscovery core must load before growth');
  const {$,$$,esc,num,fmt,state,canonicalItems,findItem,studentProfile,hasSb,openModal}=ctx;

  async function saveGrade(grade){
    const profile={...studentProfile(),grade};
    try{
      const student=typeof window.currentStudent==='function'?window.currentStudent():null;
      if(student){profile.phone=student.phone;profile.name=student.name}
    }catch(_){/* ignore */}
    localStorage.setItem('alin_v99_student_profile',JSON.stringify(profile));
    ctx.renderStage?.();
    ctx.renderEffectiveStore?.();
    if(profile.phone&&state.schema.student_profiles&&hasSb()){
      try{await window.sb.from('student_profiles').upsert({phone:profile.phone,name:profile.name||null,grade:profile.grade||null},{onConflict:'phone'})}catch(_){/* optional service */}
    }
  }

  function reorder(id){
    const order=(window.db?.orders||[]).find(row=>String(row.id)===String(id));
    if(!order||!order.item_id){alert('تفاصيل هذا الطلب القديم غير مكتملة');return}
    for(let index=0;index<Math.max(1,num(order.qty));index++)window.addToCart?.(order.kind,String(order.item_id));
    window.openCart?.();
  }

  function renderStudentHub(){
    const root=$('#v99StudentHub');
    if(!root)return;
    let student=null;
    try{student=typeof window.currentStudent==='function'?window.currentStudent():null}catch(_){/* ignore */}
    const orders=student?(window.db?.orders||[]).filter(order=>order.student_phone===student.phone).slice(0,5):[];
    if(ctx.isDesktop()||ctx.isMobile()){
      if(!student){root.innerHTML='';return}
      root.innerHTML=`<div class="v99-section-head"><div><h2>طلباتي الأخيرة</h2><small>إعادة الطلب أو متابعة حالته بسهولة</small></div></div><article class="v99-hub-card desktop-orders-card">${orders.map(order=>`<div class="v99-order-row"><div><b>${esc(order.title||order.order_number||order.id)}</b><small>${esc(order.status||'جديد')}${order.ready_eta?` • جاهز تقريباً ${esc(order.ready_eta)}`:''}</small></div><button data-v99-action="reorder" data-id="${esc(order.id)}">أعد الطلب</button></div>`).join('')||'<p>لا توجد طلبات سابقة.</p>'}</article>`;
      return;
    }
    const loyalty=(state.tables.loyalty_accounts||[]).find(row=>student&&row.phone===student.phone);
    root.innerHTML=`<div class="v99-section-head"><div><h2>مساحة الطالب</h2><small>طلباتك ومكافآتك وخيارات الطلب الجماعي</small></div></div><div class="v99-hub-grid"><article class="v99-hub-card"><h3>آخر الطلبات</h3>${student?(orders.map(order=>`<div class="v99-order-row"><div><b>${esc(order.title||order.order_number||order.id)}</b><small>${esc(order.status||'جديد')}${order.ready_eta?` • جاهز تقريباً ${esc(order.ready_eta)}`:''}</small></div><button data-v99-action="reorder" data-id="${esc(order.id)}">أعد الطلب</button></div>`).join('')||'<p>لا توجد طلبات سابقة.</p>'):'<p>سجل دخول الطالب لرؤية طلباتك.</p>'}</article><article class="v99-hub-card"><h3>نقاط آلين</h3>${loyalty?`<div class="v99-price">${fmt(loyalty.points_balance)} نقطة</div><p>يُحتسب الرصيد من النظام الآمن فقط.</p>`:'<div class="v99-notice">لا يوجد رصيد نقاط متاح. تظهر النقاط هنا بعد تفعيل نظام النقاط وربط الحساب.</div>'}</article><article class="v99-hub-card"><h3>طلب جماعي</h3><p>اجمع طلبات زملائك في مجموعة واحدة عندما تكون الخدمة مفعلة.</p><button data-v99-action="groupOrder">إنشاء أو انضمام</button></article></div>`;
  }

  function groupOrder(){
    const ready=state.schema.group_orders&&state.schema.group_order_members;
    openModal(`<h2>الطلب الجماعي</h2>${ready?'<p>أنشئ رمز مجموعة أو أدخل رمزاً موجوداً.</p>':'<div class="v99-notice error">الخدمة غير مفعلة على قاعدة البيانات.</div>'}<div class="v99-form"><input id="v99GroupCode" placeholder="رمز المجموعة"><button data-v99-action="groupJoin" ${ready?'':'disabled'}>انضمام للمجموعة</button><button data-v99-action="groupCreate" ${ready?'':'disabled'}>إنشاء مجموعة</button><div id="v99FormMsg"></div></div>`);
  }

  async function groupWrite(mode){
    const message=$('#v99FormMsg'),code=$('#v99GroupCode')?.value.trim().toUpperCase(),profile=studentProfile();
    if(!hasSb()){if(message)message.innerHTML='<div class="v99-notice error">الاتصال غير متاح.</div>';return}
    try{
      if(mode==='create'){
        const value=code||`ALIN-${Math.random().toString(36).slice(2,7).toUpperCase()}`;
        const {data,error}=await window.sb.from('group_orders').insert({code:value,status:'open',owner_contact:profile.phone||null}).select().single();
        if(error)throw error;
        if(message)message.innerHTML=`<div class="v99-notice success">تم إنشاء المجموعة: <b>${esc(data.code)}</b></div>`;
      }else{
        if(!code)throw new Error('اكتب رمز المجموعة');
        const {data:group,error:findError}=await window.sb.from('group_orders').select('id,code').eq('code',code).eq('status','open').maybeSingle();
        if(findError)throw findError;
        if(!group)throw new Error('المجموعة غير موجودة');
        const {error}=await window.sb.from('group_order_members').insert({group_order_id:group.id,contact:profile.phone||null,name:profile.name||null});
        if(error)throw error;
        if(message)message.innerHTML='<div class="v99-notice success">تم الانضمام للمجموعة.</div>';
      }
    }catch(error){if(message)message.innerHTML=`<div class="v99-notice error">لم يتم الحفظ: ${esc(error.message||'تحقق من الصلاحيات')}</div>`}
  }

  async function safeTable(name){
    if(!hasSb())return null;
    try{
      const {data,error}=await window.sb.from(name).select('*').limit(100);
      if(error)throw error;
      state.schema[name]=true;
      return data||[];
    }catch(_){state.schema[name]=false;return null}
  }

  async function loadGrowthData(){
    const names=['bundles','bundle_items','product_reviews'];
    const results=await Promise.all(names.map(name=>safeTable(name)));
    names.forEach((name,index)=>{state.tables[name]=results[index]||[]});
    ctx.renderEffectiveStore?.();
    renderStudentHub();
    renderAdminGrowth();
  }

  function renderAdminGrowth(){
    $('#v99AdminPanel')?.remove();
  }

  async function editMerch(kind,id){
    const item=findItem(kind,id);
    if(!item)return;
    const deal=prompt('سعر العرض (اتركه فارغاً للإلغاء)',item.dealPrice||'');
    const start=prompt('بداية العرض ISO أو فارغ',item.dealStart||'');
    const end=prompt('نهاية العرض ISO أو فارغ',item.dealEnd||'');
    const badge=prompt('الشارة',item.badge||'');
    const prep=prompt('دقائق التجهيز',item.prep||'');
    if([deal,start,end,badge,prep].some(value=>value===null))return;
    try{
      await window.update(kind==='booklet'?'booklets':'products',{deal_price:deal?num(deal):null,deal_start:start||null,deal_end:end||null,badge:badge||null,prep_minutes:prep?num(prep):null},{id});
      await window.load();
      alert('تم حفظ بيانات العرض');
    }catch(error){alert(`تعذر الحفظ.\n${error.message||''}`)}
  }

  function decorateAdminRows(){
    if(!$('#adminContent'))return;
    for(const row of $$('#adminContent .row')){
      if(row.querySelector('[data-v99-merch]'))continue;
      const text=row.textContent;
      const item=canonicalItems().find(candidate=>text.includes(candidate.title));
      if(!item)continue;
      const button=document.createElement('button');
      button.type='button';button.dataset.v99Merch='1';button.textContent='إدارة العرض';
      button.onclick=()=>editMerch(item.kind,item.id);
      (row.querySelector('.row-actions')||row).appendChild(button);
    }
  }

  function handoff(id){
    const order=(window.db?.orders||[]).find(row=>String(row.id)===String(id));
    if(!order?.handoff_token)return;
    openModal(`<h2>رمز تسليم الطلب</h2><p>اعرض هذا الرمز للمكتبة. لا يؤكد التسليم وحده؛ التحقق يتم من النظام المصرّح.</p><div class="v99-print-token">${esc(order.handoff_token)}</div><button onclick="window.print()">طباعة الرمز</button>`);
  }

  function enhanceTracking(event){
    const box=$('#trackOrderResult');
    if(!box)return;
    const code=String(event.detail?.code||$('#trackOrderInput')?.value||'').trim();
    const order=(window.db?.orders||[]).find(row=>[row.id,row.order_number,row.tracking_code].map(String).includes(code));
    if(!order)return;
    const extras=[];
    if(order.ready_eta&&!String(box.textContent||'').includes('الجاهزية المتوقعة'))extras.push(`الجاهزية المتوقعة: ${esc(order.ready_eta)}`);
    if(order.handoff_token&&['ready','completed'].includes(order.status))extras.push(`<button data-v99-action="handoff" data-id="${esc(order.id)}">رمز الاستلام</button>`);
    if(extras.length)box.insertAdjacentHTML('beforeend',`<div class="v99-notice">${extras.join('<br>')}</div>`);
  }

  Object.assign(ctx,{saveGrade,reorder,renderStudentHub,groupOrder,groupWrite,safeTable,loadGrowthData,renderAdminGrowth,editMerch,decorateAdminRows,handoff,enhanceTracking});
  window.v99Reorder=reorder;
  window.v99EditMerch=editMerch;
})();

